var e=[{id:`L2_1`,type:`dialog`,speaker:`JACKO_GUILTY_CA_NULL`,text:{KOREA:`내가 마지막까지 당신의 힘이 돼줄게. 가능성이 낮아도 괜찮아.`,JPN:`私が最後まで貴方の力になる。確率的に可能性が低いとしても大丈夫。`,ENG:`I'll be there to help you until the end. It's okay if the chances are slim. `,TWN:`I'll be there to help you until the end. It's okay if the chances are slim. `},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JACKO_GUILTY_CA_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`JACKO_GUILTY_CA_NULL`,text:{KOREA:`인간에겐 헛수고가 필요할 때도 있다고……친구가 그랬어.`,JPN:`人間には必要な無駄があるって……友達が言ってた。`,ENG:`A friend once told me... that meaningless effort is sometimes necessary for humans.`,TWN:`A friend once told me... that meaningless effort is sometimes necessary for humans.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JACKO_GUILTY_CA_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};